#include<bits/stdc++.h>
using namespace std;
struct node
{
	int a,b,c;
	node(){}
	node(int x):a(x/100),b(x/10%10),c(x%10){}
	node(int x,int y):a(x),b(y),c(0){}
	node(int x,int y,int z):a(x),b(y),c(z){}
	node(initializer_list<int> x){int cnt=0;for(int i:x){cnt++;if(cnt==1){a=i;}else if(cnt==2){b=i;}else if(cnt==3){c=i;}}}
	void print(char x=' ')
	{
		printf("%d%c%d%c%d",a,x,b,x,c);
	}
	bool operator==(node x)
	{
		return a==x.a&&b==x.b&&c==x.c;
	}
	friend bool operator<(const node &a,const node &b)
	{
		return a.a<b.a||(a.a==b.a&&a.b<b.b)||(a.a==b.a&&a.b==b.b&&a.c<b.c);
	}
	friend bool operator>(const node &a,const node &b)
	{
		return b<a;
	}
};
int a[11],b[11],c[11],n;
void dfs(int x,set<node>&ans)
{
	if(x>n)
	{
		memcpy(c,b,sizeof(b));
		if(c[4])
		{
			if(!c[1]&&c[2])
			{
				c[1]=c[4]-c[2];
			}
			if(!c[2]&&c[1])
			{
				c[2]=c[4]-c[1];
			}
			if(!c[3]&&c[7])
			{
				c[3]=c[7]-c[4];
			}
		}
		if(c[5])
		{
			if(!c[2]&&c[3])
			{
				c[2]=c[5]-c[3];
			} 
			if(!c[3]&&c[2])
			{
				c[3]=c[5]-c[2];
			}
			if(!c[1]&&c[7])
			{
				c[1]=c[7]-c[5];
			}
		}
		if(c[6])
		{
			if(!c[1]&&c[3])
			{
				c[1]=c[6]-c[3];
			}
			if(!c[3]&&c[1])
			{
				c[3]=c[6]-c[1];
			}
			if(!c[2]&&c[7])
			{
				c[2]=c[7]-c[6];
			}
		}
		if(c[1]>=1&&c[2]>=c[1]&&c[3]>=c[2])
		{
			if(c[4]&&c[4]!=c[1]+c[2])
			{
				return;
			}
			if(c[5]&&c[5]!=c[2]+c[3])
			{
				return;
			}
			if(c[6]&&c[6]!=c[1]+c[3])
			{
				return;
			}
			if(c[7]&&c[7]!=c[1]+c[2]+c[3])
			{
				return;
			}
			ans.insert(node({c[1],c[2],c[3]}));
		}
	}
	else
	{
		for(int i=1;i<=7;i++)
		{
			if(!b[i])
			{
				b[i]=a[x];
				dfs(x+1,ans);
				b[i]=0;
			}
		}
	}
}
int main()
{
	int t;
	scanf("%d",&t);
	while(t--)
	{
		scanf("%d",&n);
		for(int i=1;i<=n;i++)
		{
			scanf("%d",&a[i]);
		}
		set<node> ans;
		dfs(0,ans);
		printf("%d\n",(int)ans.size());
	}
	return 0;
}
